<script>
function parseINR(raw){if(raw===undefined||raw===null)return NaN;const c=String(raw).replace(/[,\s₹%]/g,'');if(c==='')return NaN;const n=parseFloat(c);return isFinite(n)?n:NaN;}
function showError(msg){const b=document.getElementById('errorBanner');b.textContent=msg;b.classList.add('visible');setTimeout(()=>b.classList.remove('visible'),6000);}
function fmtINR(n){if(!isFinite(n))return '—';return '₹'+n.toLocaleString('en-IN',{maximumFractionDigits:0});}
function fmtL(n){if(!isFinite(n))return '—';if(n >= 100000)return '₹'+(n/100000).toFixed(2)+' L';return fmtINR(n);}

let currentEntity = 'pvtltd';
let currentArea = 'tier1';
let currentOffice = 'rented';
let currentMF = 'no';
let currentEngagement = 'standard';

function setEntity(b){const e=b.closest?(b.closest('.toggle-btn')||b):b;currentEntity=e.dataset.entity;e.parentElement.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));e.classList.add('active');if(document.getElementById('resultSection').classList.contains('visible'))calculate(true);}
function setArea(b){const e=b.closest?(b.closest('.toggle-btn')||b):b;currentArea=e.dataset.area;e.parentElement.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));e.classList.add('active');if(document.getElementById('resultSection').classList.contains('visible'))calculate(true);}
function setOffice(b){const e=b.closest?(b.closest('.toggle-btn')||b):b;currentOffice=e.dataset.office;e.parentElement.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));e.classList.add('active');if(document.getElementById('resultSection').classList.contains('visible'))calculate(true);}
function setMF(b){const e=b.closest?(b.closest('.toggle-btn')||b):b;currentMF=e.dataset.mf;e.parentElement.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));e.classList.add('active');if(document.getElementById('resultSection').classList.contains('visible'))calculate(true);}
function setEngagement(b){const e=b.closest?(b.closest('.toggle-btn')||b):b;currentEngagement=e.dataset.engagement;e.parentElement.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));e.classList.add('active');if(document.getElementById('resultSection').classList.contains('visible'))calculate(true);}

function compute(entity, area, office, numISPs, mf, engagement){
    // Line item definitions
    const items = [];
    // 1. MCA Registration
    const mca = entity === 'pvtltd' ? 25000 : 18000;
    items.push({label: 'MCA Registration', desc: entity === 'pvtltd' ? 'DIN/DSC, name, incorporation, MOA stamp duty, PAN/TAN' : 'DPIN/DSC, name, FiLLiP, LLP Agreement stamp duty, PAN', amt: mca, cat: 'govt'});
    // 2. IRDAI fee
    items.push({label: 'IRDAI Registration Fee', desc: 'FORM A application fee (one-time non-refundable)', amt: 5000, cat: 'govt'});
    // 3. Professional fees
    const profFees = {diy:25000, standard:75000, premium:125000}[engagement];
    items.push({label: 'Patron Accounting Service Fee', desc: engagement === 'diy' ? 'Filing assistance only (DIY tier)' : (engagement === 'standard' ? 'End-to-end MCA + IRDAI + PO coordination' : 'Premium: insurer tie-ups + presentation support + 6-mo handholding'), amt: profFees, cat: 'pro'});
    // 4. Principal Officer training
    items.push({label: 'Principal Officer Training', desc: 'IRDAI-prescribed training + III examination', amt: 12000, cat: 'training'});
    // 5. ISP training
    const ispTraining = numISPs * 4000;
    items.push({label: 'ISP Training (×' + numISPs + ')', desc: '50-hr ISMP + III examination per ISP', amt: ispTraining, cat: 'training'});
    // 6. Office infra
    const officeInfra = office === 'rented' ? 35000 : 5000;
    items.push({label: 'Office Infrastructure', desc: office === 'rented' ? 'Furniture + equipment + initial setup (deposit excluded)' : 'Minimal furniture & equipment (own premises)', amt: officeInfra, cat: 'training'});
    // 7. PI insurance
    const pi = area === 'tier1' ? 22000 : 7000;
    items.push({label: 'Professional Indemnity Insurance', desc: 'Year 1 premium; cover at 2× remuneration or net worth minimum', amt: pi, cat: 'training'});
    // 8. First-year compliance
    const compl = entity === 'pvtltd' ? 55000 : 42000;
    items.push({label: 'First-Year Statutory Compliance', desc: entity === 'pvtltd' ? 'Audit + ITR + MGT-7A + AOC-4 + GST (if applicable)' : 'Audit (if turnover &gt; ₹25L) + ITR + Form 8 + Form 11 + GST', amt: compl, cat: 'training'});
    // 9. Mutual fund add-on
    const mfCost = mf === 'yes' ? 8000 : 0;
    if(mf === 'yes'){
        items.push({label: 'Mutual Fund Distribution (AMFI ARN + NISM)', desc: 'Per FSE: NISM Series V-A + AMFI registration (one-time)', amt: mfCost, cat: 'optional'});
    }

    const totalCash = items.reduce((s, i) => s + i.amt, 0);
    const govt = items.filter(i => i.cat === 'govt').reduce((s,i)=>s+i.amt,0);
    const pro = items.filter(i => i.cat === 'pro').reduce((s,i)=>s+i.amt,0);
    const trainingCompl = items.filter(i => i.cat === 'training' || i.cat === 'optional').reduce((s,i)=>s+i.amt,0);
    const netWorth = area === 'tier1' ? 5000000 : 1000000;

    // Break-even at ~7-12% blended commission on premium under management
    // setup recovered at: totalCash / 0.10 = approx premium volume needed
    const breakeven = totalCash / 0.10;

    return {items, totalCash, govt, pro, trainingCompl, netWorth, breakeven};
}

function calculate(silent){
    const numISPs = parseINR(document.getElementById('numISPs').value);
    if(!isFinite(numISPs) || numISPs < 1 || numISPs > 50){showError('Enter a valid ISP count (1-50).');return;}

    const r = compute(currentEntity, currentArea, currentOffice, numISPs, currentMF, currentEngagement);

    document.getElementById('resHeadline').textContent = fmtL(r.totalCash);
    document.getElementById('resHeadlineMeta').textContent = (currentEntity === 'pvtltd' ? 'Private Limited' : 'LLP') + ' · ' + (currentArea === 'tier1' ? 'Larger urban' : 'Smaller city') + ' · ' + (currentEngagement === 'diy' ? 'DIY engagement' : (currentEngagement === 'standard' ? 'Standard engagement' : 'Premium engagement')) + ' · ' + numISPs + ' ISP' + (numISPs > 1 ? 's' : '') + ' · MF distribution: ' + currentMF;

    document.getElementById('resGovt').textContent = fmtL(r.govt);
    document.getElementById('resPro').textContent = fmtL(r.pro);
    document.getElementById('resTraining').textContent = fmtL(r.trainingCompl);
    document.getElementById('resNetWorth').textContent = fmtL(r.netWorth);
    document.getElementById('resTotalCapital').textContent = fmtL(r.totalCash + r.netWorth);
    document.getElementById('resBreakeven').textContent = fmtL(r.breakeven) + ' premium';

    const tbody = document.getElementById('costTableBody');
    tbody.innerHTML = '';
    r.items.forEach(item => {
        const tr = document.createElement('tr');
        if(item.cat === 'optional') tr.className = 'optional';
        tr.innerHTML = '<td>' + item.label + '</td><td class="desc">' + item.desc + '</td><td>' + fmtINR(item.amt) + '</td>';
        tbody.appendChild(tr);
    });
    document.getElementById('totalCash').innerHTML = '<strong>' + fmtL(r.totalCash) + '</strong>';

    const section = document.getElementById('resultSection');
    section.classList.add('visible');
    if(!silent) requestAnimationFrame(function(){requestAnimationFrame(function(){section.scrollIntoView({behavior:'smooth',block:'start'});});});
}

function resetCalc(){
    document.getElementById('numISPs').value = '3';
    document.querySelectorAll('.toggle-group').forEach(g=>{g.querySelectorAll('.toggle-btn').forEach(x=>x.classList.remove('active'));});
    document.querySelector('.toggle-btn[data-entity="pvtltd"]').classList.add('active');
    document.querySelector('.toggle-btn[data-area="tier1"]').classList.add('active');
    document.querySelector('.toggle-btn[data-office="rented"]').classList.add('active');
    document.querySelector('.toggle-btn[data-mf="no"]').classList.add('active');
    document.querySelector('.toggle-btn[data-engagement="standard"]').classList.add('active');
    currentEntity = 'pvtltd'; currentArea = 'tier1'; currentOffice = 'rented'; currentMF = 'no'; currentEngagement = 'standard';
    document.getElementById('resultSection').classList.remove('visible');
    document.getElementById('errorBanner').classList.remove('visible');
}

function toggleFaq(e){const b=e.closest?(e.closest('.faq-question')||e):e;const it=b.closest('.faq-item');if(!it)return;const o=it.classList.contains('open');document.querySelectorAll('.faq-item').forEach(i=>{i.classList.remove('open');const q=i.querySelector('.faq-question');if(q)q.setAttribute('aria-expanded','false');});if(!o){it.classList.add('open');b.setAttribute('aria-expanded','true');}}

document.querySelectorAll('input[type="number"], input[type="text"]').forEach(i=>{i.addEventListener('keydown',function(e){if(e.key==='Enter'){e.preventDefault();calculate();}});});

const navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',()=>{const s=document.querySelectorAll('section[id], header[id]');let c='';s.forEach(x=>{const t=x.offsetTop-100;if(window.pageYOffset>=t)c=x.getAttribute('id');});navLinks.forEach(l=>{l.classList.toggle('active',l.getAttribute('href')==='#'+c);});});
</script>


